  import java.util.ArrayList;
  import java.util.Date;
  import java.util.HashMap;
  import java.util.List;
  import java.util.Map;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  import sailpoint.api.Certificationer;
  import sailpoint.object.Application;
  import sailpoint.object.Attributes;
  import sailpoint.object.Bundle;
  import sailpoint.object.Certification;
  import sailpoint.object.CertificationEntity;
  import sailpoint.object.CertificationItem;
  import sailpoint.object.Custom;
  import sailpoint.object.EmailOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.RoleTarget;
  import sailpoint.object.TaskResult;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Message;
  import sailpoint.tools.Util;


  String KEY_ADDS_APP_NAME = "AD-DS";
  String KEY_TASK_NAME = "RCA-ReassignAccessReviews";
  String RCA_MANAGER_MAPPING_STORE = "Ascension-Custom-RCA-MapManagers";
  String KEY_USER_MANAGER_MAPPING_NAME = "managerMapping";
  String KEY_EMAIL_TEMPLATE_NAME = "Ascension-EmailTemplate-RCAAttestationAccessReview-Initial";
  List unidentifiedManagerEmpIDList = new ArrayList();
  List unidentifiedUserList = new ArrayList();
  TaskResult taskResult = context.getObjectByName(TaskResult.class, KEY_TASK_NAME);
  Log logger = LogFactory.getLog("sailpoint.ascension.rca.task.ReassignAccessReviews");

  private void sendEmail(Identity certifier, Attributes emailArgs)
  {
    String toEmail = certifier.getEmail();
    if (Util.isNullOrEmpty(toEmail))
      return;
    EmailOptions emailOpts = new EmailOptions();
    emailOpts.setVariables(emailArgs);
    emailOpts.setTo(toEmail);
    EmailTemplate emailTemplate = null;
    try
    {
      emailTemplate = context.getObjectByName(EmailTemplate.class, KEY_EMAIL_TEMPLATE_NAME);
      context.sendEmailNotification(emailTemplate, emailOpts);
    }
    catch (EmailException e)
    {
      taskResult.addMessage(Message.error( "RCA || EmailException  : " + e.getMessage()));
    }
    catch (GeneralException e)
    {
      taskResult.addMessage(Message.error( "RCA || GeneralException  : " + e.getMessage()));
    }
  }

  private String getName(List certifiers, Date createdDate)
  {
    String certName = "RCA Access Review Reassigned to ";
    if(Util.isNotNullOrEmpty(certifiers.get(0).getDisplayName()))
      certName = certName + certifiers.get(0).getDisplayName() + " created on " + Util.dateToString(createdDate);
    else 
      certName = certName + certifiers.get(0).getName() + " created on " + Util.dateToString(createdDate);
    return certName;
  }

  private List getCertifierIdentities(CertificationEntity entity, Map userManagerMap) throws GeneralException
  {
    List certifiers = new ArrayList();
    String rcaUserName = null;
    String rcaAccessReviewer = null;

    List certItems = entity.getItems();
    if (certItems != null && !certItems.isEmpty())
    {
      for (CertificationItem certItem : certItems)
      {
        //taskResult.addMessage(Message.info("certItem: "+certItem));
        if (certItem.getRoleDetection() == null)
          continue;
        List roleTargets = certItem.getRoleDetection().getTargets();
        //taskResult.addMessage(Message.info("roleTargets: "+roleTargets));
        if (null == roleTargets || roleTargets.isEmpty())
          continue;
        for (RoleTarget roleTarget : roleTargets)
        {
          String accountDisplayName = roleTarget.getDisplayName();
          taskResult.addMessage(Message.info("accountDisplayName: "+accountDisplayName));
          if (Util.isNullOrEmpty(accountDisplayName))
            continue;
          rcaUserName = accountDisplayName.substring(accountDisplayName.indexOf("\\") + 1);
          //taskResult.addMessage(Message.info("rcaUserName: "+rcaUserName));
          if (Util.isNotNullOrEmpty(userManagerMap.get(rcaUserName)))
          {
            rcaAccessReviewer = userManagerMap.get(rcaUserName);
            taskResult.addMessage(Message.info("rcaAccessReviewer: "+rcaAccessReviewer));
            break;
          }
          else
            continue;
        }
      }
    }
    if (Util.isNullOrEmpty(rcaAccessReviewer))
    {
      if(Util.isNotNullOrEmpty(rcaUserName))
        unidentifiedUserList.add(rcaUserName);
      return null;
    }

    //Identity reviewerIden = context.getObjectByName(Identity.class, rcaAccessReviewer);
    Identity reviewerIden = context.getUniqueObject(Identity.class, Filter.or(Filter.eq("employeeId", rcaAccessReviewer ), Filter.eq("name", rcaAccessReviewer ),Filter.eq("email", rcaAccessReviewer )));
    if(null == reviewerIden)
    {
      if(Util.isNotNullOrEmpty(rcaAccessReviewer))
        unidentifiedManagerEmpIDList.add(rcaAccessReviewer);
      return null;
    }
    certifiers.add(reviewerIden);
    return certifiers;
  }

  public String reassignRCACertifications(String certificationName) throws GeneralException
  {
    int commmitCount = 0;
    String reassignComment = "This RCA access review has been reassigned by the system.";
    Identity requester = context.getObjectByName(Identity.class, "IDM Team");
    Custom rcaManagerMappingStore = context.getObjectByName(Custom.class, RCA_MANAGER_MAPPING_STORE);
    if (rcaManagerMappingStore == null)
      throw new RuntimeException(
      "RCA || Custom object does not exists! Custom obj: " + RCA_MANAGER_MAPPING_STORE);

    List userManagerList = rcaManagerMappingStore.getList(KEY_USER_MANAGER_MAPPING_NAME);
    if (null == userManagerList || userManagerList.isEmpty())
    {
      taskResult.addMessage(new Message(Message.Type.Warn, "RCA || user-manager mapping is unavailable in the custom object."));
      logger.warn("RCA || user-manager mapping is unavailable in the custom object.");
    }
    Map userManagerMap = new HashMap();
    for (String userManagerCSV : userManagerList)
    {
      taskResult.addMessage(Message.info("userManagerList.get(0): "+userManagerCSV.substring(0, userManagerCSV.indexOf(","))));
      taskResult.addMessage(Message.info("userManagerList.get(1): "+userManagerCSV.substring(userManagerCSV.indexOf(",")+1)));
      userManagerMap.put(userManagerCSV.substring(0, userManagerCSV.indexOf(",")) , userManagerCSV.substring(userManagerCSV.indexOf(",")+1));
    }

    Certification defaultCert = context.getObject(Certification.class, certificationName);
    List entities = defaultCert.getEntities();
    for (CertificationEntity entity : entities)
    {
      List newEntityList = new ArrayList();
      newEntityList.add(entity.getId());

      List certifiers = getCertifierIdentities(entity, userManagerMap);
      if (null == certifiers || certifiers.isEmpty())
      {
        //taskResult.addMessage(Message.info("certifiers: "+  certifiers));
        continue;
      }
      String reassignmentName = getName(certifiers, entity.getCreated());
      if (Util.isNullOrEmpty(reassignmentName))
      {
        taskResult.addMessage(Message.info("reassignmentName: "+  reassignmentName));
        continue;
      }
      taskResult.addMessage(Message.info("reassignmentName: " + reassignmentName));
      defaultCert.bulkReassignEntities(requester, newEntityList, certifiers.get(0), reassignmentName, reassignmentName, reassignComment);
      context.saveObject(defaultCert);
      context.commitTransaction();
      //taskResult.addMessage(Message.info("Test1"));
      /*Attributes emailArgs = new Attributes();
      emailArgs.put("ownerName", certifiers.get(0).getDisplayName());
      emailArgs.put("requesterName", "IDM Team");
      emailArgs.put("certification", defaultCert);
      sendEmail(certifiers.get(0), emailArgs);*/
      commmitCount++;
    }
    new Certificationer(context).refresh(defaultCert);
    if(!unidentifiedUserList.isEmpty())
      taskResult.addMessage(Message.warn( "RCA || unidentifiedUserList : " + unidentifiedUserList));
    if(!unidentifiedManagerEmpIDList.isEmpty())
      taskResult.addMessage(Message.warn( "RCA || unidentifiedManagerEmpIDList : " + unidentifiedManagerEmpIDList));
    taskResult.addMessage(Message.warn( "RCA || commmitCount : " + commmitCount));
    return "new certification created = " + commmitCount;
  }
  
  public String getManagerUserMap()
  {
    Custom rcaManagerMappingStore = context.getObjectByName(Custom.class, RCA_MANAGER_MAPPING_STORE);
    List userManagerList = rcaManagerMappingStore.getList(KEY_USER_MANAGER_MAPPING_NAME);

    Map userManagerMap = new HashMap();
    for (String userManagerCSV : userManagerList)
    {
      userManagerMap.put(userManagerCSV.substring(0, userManagerCSV.indexOf(",")) , userManagerCSV.substring(userManagerCSV.indexOf(",")+1));
    }
    return userManagerMap.toString();
  
  }

  reassignRCACertifications("RCA Access Review for Ascension-RCAAttestationReviewer created on 12/14/22 11:40:44 AM CST");
//getManagerUserMap();
